const HEAT_P  = new Set(['cellular-shades','sun-screens','motorized-exterior','awnings','faux-wood-blinds'])
const PRIV_P  = new Set(['roller-shades','zebra-shades','blackout-curtains','aluminum-blinds','vertical-blinds'])
const LUX_P   = new Set(['shangri-la-shades','roman-shades','sheer-drapes','curtains-drapery','plantation-shutters'])
const SMART_P = new Set(['motorized-shading','panel-track-blinds'])
const NAT_P   = new Set(['woven-wood-shades','sheer-shades'])

function productCategory(product: string): string {
  if (HEAT_P.has(product))  return 'heat-control'
  if (PRIV_P.has(product))  return 'privacy'
  if (LUX_P.has(product))   return 'luxury-aesthetic'
  if (SMART_P.has(product)) return 'smart-modern'
  if (NAT_P.has(product))   return 'natural'
  return 'privacy'
}

export function getCityProductParagraph(city: string, product: string): string {
  const profile = CITY_PROFILES[city]
  if (!profile) return ''
  const nb   = profile.neighborhoods[0]
  const nb2  = profile.neighborhoods[1] ?? nb
  const pName = PRODUCT_SLUGS[product] ?? product
  const cName = cityName(city)
  const cat  = productCategory(product)

  if (profile.type === 'inland-hot') {
    if (cat === 'heat-control') return `${cName} summers are relentless — ${profile.climate.toLowerCase()} In neighborhoods like ${nb} and ${nb2}, the difference between a treated and untreated west-facing window is measurable in both temperature and energy bills. ${pName} are among the most impactful investments a ${cName} homeowner can make for summer comfort, and iL Progetto sizes and installs every unit to eliminate gaps that off-the-shelf products leave behind.`
    if (cat === 'privacy')      return `${profile.architecture} In ${nb}, homes sit on lots where afternoon privacy varies widely by orientation and neighbor proximity. Our custom ${pName.toLowerCase()} are cut to your exact window dimensions and installed with precision hardware — no light gaps, no standard-size shortfalls that compromise both privacy and aesthetics.`
    return `${cName}'s ${profile.climate.toLowerCase()} In neighborhoods like ${nb}, natural light quality is intense — which makes the choice of window treatment material critical. Our custom ${pName.toLowerCase()} are selected and installed to work with the specific light conditions of your ${cName} home.`
  }
  if (profile.type === 'coastal-luxury') {
    if (cat === 'luxury-aesthetic') return `${cName} interiors set a high bar — ${profile.architecture.toLowerCase()} In homes throughout ${nb} and ${nb2}, window treatments are a primary design element. Our ${pName.toLowerCase()} are specified with the same attention to proportion and material quality that the rest of the interior demands, and every installation is completed by our own licensed team.`
    if (cat === 'heat-control')     return `${profile.uniqueFact} In ${nb}, where glass walls and elevated exposures intensify glare, ${pName.toLowerCase()} provide the technical solution that preserves views while making interiors livable. iL Progetto specifies marine-grade hardware and UV-stable fabrics for every ${cName} installation.`
    return `${profile.uniqueFact} In ${nb} and ${nb2}, our custom ${pName.toLowerCase()} are designed around both the architectural character of the home and the specific light conditions of the coastal ${cName} environment.`
  }
  if (profile.type === 'coastal-casual') {
    if (cat === 'natural')      return `${cName}'s relaxed coastal character is perfectly matched by ${pName.toLowerCase()} — natural fibers that filter light with warm organic texture. In ${nb} and ${nb2}, these treatments coordinate seamlessly with linen, rattan, and whitewashed wood interiors. Every piece is custom-measured so proportions feel intentional.`
    if (cat === 'heat-control') return `${profile.uniqueFact} In ${nb} and ${nb2}, UV management is a year-round priority. Our custom ${pName.toLowerCase()} are specified with fabrics that handle sustained coastal sun exposure without fading, and installed with hardware rated for salt-air environments.`
    return `${profile.climate} In ${nb}, our custom ${pName.toLowerCase()} are specified with materials appropriate to the coastal environment and installed to the exact dimensions of your windows.`
  }
  if (profile.type === 'estate') {
    if (cat === 'luxury-aesthetic') return `${cName}'s architectural standards are among the most stringent in Southern California — ${profile.architecture.toLowerCase()} In ${nb} and ${nb2}, ${pName.toLowerCase()} are the expected standard. Our team prepares ARB documentation and coordinates approvals so installation proceeds without delays.`
    return `${profile.uniqueFact} In ${nb} and ${nb2}, our custom ${pName.toLowerCase()} are specified to complement the architectural character of the home and satisfy the community's review standards.`
  }
  if (profile.type === 'suburban-growing') {
    if (cat === 'heat-control') return `${cName}'s newer construction in ${nb} and ${nb2} features the open floor plans and large window runs that drive up cooling costs in summer. ${pName} installed on west and south exposures make a measurable difference in afternoon comfort and monthly energy bills.`
    if (cat === 'smart-modern') return `${profile.uniqueFact} The newer homes in ${nb} and ${nb2} are wired for smart home integration from the start, making ${pName.toLowerCase()} a natural addition. Our installer handles all programming during the installation appointment.`
    return `${profile.architecture} In ${nb} and ${nb2}, our custom ${pName.toLowerCase()} are cut to your exact window dimensions and installed by our own licensed team for the clean finish that newer construction deserves.`
  }
  return `${profile.uniqueFact} Our custom ${pName.toLowerCase()} in ${cName} are measured and installed to the exact specifications of your home, with materials selected for the specific light, humidity, and architectural conditions of neighborhoods like ${nb}.`
}

export function getCityProductH1(city: string, product: string): { prefix: string; emphasis: string; suffix: string } {
  const profile = CITY_PROFILES[city]
  const pName = PRODUCT_SLUGS[product] ?? product
  const cName = cityName(city)
  const cat = productCategory(product)
  if (profile?.type === 'coastal-luxury') {
    if (cat === 'luxury-aesthetic') return { prefix:'Custom ', emphasis:pName, suffix:` for ${cName} Homes` }
    return { prefix:'Precision ', emphasis:pName, suffix:` for ${cName} Residences` }
  }
  if (profile?.type === 'inland-hot' && cat === 'heat-control') return { prefix:'Energy-Efficient ', emphasis:pName, suffix:` for ${cName} Homes` }
  if (profile?.type === 'estate')           return { prefix:'Luxury ', emphasis:pName, suffix:` for ${cName} Estates` }
  if (profile?.type === 'suburban-growing' && cat === 'smart-modern') return { prefix:'Smart ', emphasis:pName, suffix:` for ${cName} Homes` }
  if (profile?.type === 'coastal-casual' && cat === 'natural') return { prefix:'Natural ', emphasis:pName, suffix:` for ${cName} Interiors` }
  if (profile?.type === 'urban')            return { prefix:'Professional ', emphasis:pName, suffix:` Installation in ${cName}, CA` }
  return { prefix:'Custom ', emphasis:pName, suffix:` in ${cName} — Measured & Installed` }
}

export function getCityProductH2(city: string, product: string): string {
  const profile = CITY_PROFILES[city]
  const pName = PRODUCT_SLUGS[product] ?? product
  const cName = cityName(city)
  const cat = productCategory(product)
  if (profile?.type === 'coastal-luxury')                              return `The Case for ${pName} in a ${cName} Home`
  if (profile?.type === 'inland-hot' && cat === 'heat-control')       return `Why ${cName} Homeowners Rely on ${pName}`
  if (profile?.type === 'inland-hot')                                  return `${pName} Built for the ${cName} Climate`
  if (profile?.type === 'estate')                                      return `${pName} That Meet ${cName} Standards`
  if (profile?.type === 'suburban-growing')                            return `The Right ${pName} for ${cName} Homes`
  if (profile?.type === 'coastal-casual' && cat === 'natural')        return `${pName} for the ${cName} Lifestyle`
  if (profile?.type === 'coastal-casual')                              return `${pName} Designed for ${cName} Living`
  return `Why ${pName} Are Ideal for ${cName} Homes`
}

export function getCityInstallParagraph(city: string, product: string): string {
  const profile = CITY_PROFILES[city]
  const pName = (PRODUCT_SLUGS[product] ?? product).toLowerCase()
  const cName = cityName(city)
  const nb = profile?.neighborhoods[0] ?? cName
  if (profile?.type === 'coastal-luxury') return `Once you approve the specification, your ${pName} are custom-fabricated and scheduled for installation by our own licensed team — California Contractor License #1127055. We never use subcontractors. In ${cName} homes where finish quality is non-negotiable, our installer arrives with everything pre-assembled to your measurements, completes the full installation in a single appointment, and walks you through operation before leaving. We typically schedule ${cName} installations within 3-5 business days of your consultation.`
  if (profile?.type === 'inland-hot')     return `After your in-home measurement, your ${pName} are custom-fabricated to your exact window dimensions and returned for professional installation — usually within 3-5 business days. Our licensed installer (CA License #1127055) handles all mounting, hardware calibration, and mechanism adjustment at your ${nb} home, and walks you through operation before leaving. Most ${cName} installations are complete in a single half-day appointment.`
  if (profile?.type === 'estate')         return `Every ${pName} installation in ${cName} is handled by our own licensed team — California Contractor License #1127055 — with no subcontractors at any stage. We manage the full process from measurement through installation, including any documentation required by the ${cName} Architectural Review Board. Your installer arrives with all components pre-assembled, completes the work in a single appointment, and provides a full operation walkthrough before leaving.`
  if (profile?.type === 'suburban-growing') return `Your ${pName} are custom-fabricated after measurement and installed by our own licensed team — CA License #1127055 — typically within 3-5 business days of your consultation. Most ${cName} installations in communities like ${nb} are completed in a single half-day appointment. We handle all mounting, alignment, and calibration, then walk you through operation before we leave. No subcontractors, no surprises.`
  return `Following measurement, your ${pName} are custom-built to your exact window dimensions and installed by our licensed team — California Contractor License #1127055. We serve ${cName} with availability typically within 3-5 business days, and most installations are completed in a single appointment. Our installer handles all hardware, adjustment, and calibration at your ${nb} home, and demonstrates operation before leaving. We never use subcontractors.`
}
